// Poll Amazon SP-API until the report reaches a terminal status.
const reportId = $('Create Report').first().json.reportId;
const accessToken = $('Get Access Token').first().json.access_token;
const endpoint = $('Config').first().json.sp_api_endpoint;

const POLL_INTERVAL_MS = 10_000;
const MAX_ATTEMPTS = 30;

let lastResponse = null;

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://${endpoint}/reports/2021-06-30/reports/${reportId}`,
    headers: { 'x-amz-access-token': accessToken },
    json: true,
  });

  lastResponse = response;

  if (response.processingStatus === 'DONE') {
    return [{ json: response }];
  }
  if (['FATAL', 'CANCELLED'].includes(response.processingStatus)) {
    throw new Error('Report failed: ' + response.processingStatus);
  }

  await new Promise(r => setTimeout(r, POLL_INTERVAL_MS));
}

throw new Error('Timed out after ' + MAX_ATTEMPTS + ' attempts. Last status: ' + lastResponse?.processingStatus);

const items = $input.all();
for (const item of items) {
  if (item.binary?.data) {
    item.binary.data.fileExtension = 'gz';
  }
}
return items;

// Generic TSV parser for Amazon SP-API reports.
// Works with any tab-separated report format.
const binary = $input.first().binary || {};
const binaryKeys = Object.keys(binary);
if (binaryKeys.length === 0) throw new Error('No binary data on input');

const buf = await this.helpers.getBinaryDataBuffer(0, binaryKeys[0]);
const text = buf.toString('utf-8');

const lines = text.split(/\r?\n/).filter(l => l.trim().length > 0);
if (lines.length < 2) throw new Error('Empty or header-only report');

const headers = lines[0].split('\t').map(h => h.trim());
const rows = lines.slice(1).map(line => {
  const cells = line.split('\t');
  const row = {};
  headers.forEach((h, i) => row[h] = cells[i] !== undefined ? cells[i].trim() : '');
  return row;
});

// Return each row as a separate n8n item for downstream processing
return rows.map(row => ({ json: row }));
